需求：有一个从vine.co爬取下来的数据集，需要对视频描述中的HashTag进行提取与计数首先筛选视频描述中拥有HashTag（以#开头的单词或短语）的条目handle_data.py12345678910111213141516171819202122#得到带hash的视频描述与视频链接#解决编码问题，忽略警告f_video_text = open(&quot;video_text.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url = open(&quot;video_download_link.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)#要写入的文件f_video_text_hash = open(&quot;video_text_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)e = &apos;#&apos; #以‘#’号标识while 1:#分别读取下一行 line_video_text = f_video_text.readline() line_video_url = f_video_url.readline() if not line_video_text: break#如果包含HashTag if (e in line_video_text): f_video_text_hash.write(line_video_text) f_video_url_hash.write(line_video_url)f_video_url.close()f_video_text.close() 遍历得到的文件，提取所有的HashTag并做词频统计handle_hash.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546# 统计hash总数与词频import collectionsf_video_text_hash = open(&quot;video_text_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_handle_hash = open(&quot;handle_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []while 1: line_video_text = f_video_text_hash.readline() if not line_video_text: break else: slotList += subString1(line_video_text) #将所有HashTag存进listresult = collections.Counter(slotList) #词频统计#ss = str(result) #词频统计结果转换成字符串并存文件# f_handle_hash.write(ss)#print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) #词频统计结果转换成字符串并存文件 f_handle_hash.write(ss+&apos;
&apos;) #print(ss)f_video_text_hash.close()f_handle_hash.close() 以上是处理数据集1：n条video:::text对应n条video:::url，顺序数量一一对应。后来又有了数据集2：n条video:::text对应m条video:::url,而且顺序不对应，两者间也不具备完全的包含关系。首先是获得含有hashtag的数据集合video_text_hash.txtget_video_text_hash.py12345678910111213#得到带hash的视频描述f_video_text = open(&quot;location_videos_description&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)e = &apos;#&apos;while 1: line_video_text = f_video_text.readline() if not line_video_text: break if (e in line_video_text): f_video_text_hash.write(line_video_text)f_video_text.close() 然后将这个数据集2的video_text_hash.txt（复制成video_text_hash_2.txt）和数据集1的video_text_hash.txt（复制成video_text_hash_1.txt）比较，去除重复条目得到video_text_hash_3.txt，重复的条目存到video_cover.txtget_video_text_hash_off_cover.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051import re#data1与data2的video_text_hash去重f1_video_text = open(&quot;video_text_hash_1.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_text_hash_2.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash_3.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_cover = open(&quot;video_cover.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = [] #用list存video_text_hash_1.txt的video的idwhile 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) list_1.append(each_id[0])#print(list_1) #data1的id listdict_2 = &#123;&#125; #用dict存video_text_hash_2.txt的video的id：texti=1while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0]#print(dict_2) #data2的dict &#123;id:text&#125;for key in dict_2: if(key not in list_1): f_video_text_hash.write(key + &apos;::&apos; + dict_2[key] + &apos;
&apos;) else: f_video_text_cover.write(key + &apos;::&apos; + dict_2[key] + &apos;
&apos;) i+=1 if(i%5000==0): print(i)f1_video_text.close()f2_video_text.close()f_video_text_hash.close() 然后将这个数据集2的video_text_hash_3.txt（复制成video_text_hash_off_cover.txt）和数据集2的video_url.txt比较，找到缺失的url_id条目得到video_url_off.txt，清理的id_url存到video_url_hash.txtget_video_url_hash.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162import re#根据video_text_hash_off_cover.txt清洗video_url.txtf1_video_text = open(&quot;video_text_hash_off_cover.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_off = open(&quot;video_url_off.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = []while 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) list_1.append(each_id[0])#print(list_1) #data1的id listii=1dict_2 = &#123;&#125;while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0] ii += 1 if (ii % 5000 == 0): print(ii)#print(dict_2) #data2的dict &#123;id:text&#125;print(&quot;开始清洗&quot;)ii=1for i in list_1: if(i in dict_2): try: f_video_url_hash.write(i + &apos;::::&apos; + dict_2[i] + &apos;
&apos;) except IndexError: print(&quot;c1&quot;) else: try: f_video_url_off.write(i + &apos;
&apos;) except IndexError: print(&quot;c2&quot;) ii+=1 if(ii%5000==0): print(ii)f1_video_text.close()f2_video_text.close()f_video_url_hash.close() 将video_text_hash_off_cover.txt依据video_url_off.txt清除缺失url的条目得到最终video_text_hash_4.txt12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758import re#将video_text_hash_off_cover.txt依据video_url_off.txt清除缺失url项f1_video_text = open(&quot;video_url_off.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_text_hash_off_cover.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash_4.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = []while 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: #each_id = getId(line_video_text) rule = r&apos;(.*?)
&apos; slotList = re.findall(rule, line_video_text) list_1.append(slotList[0])#print(list_1) #data1的id listdict_2 = &#123;&#125;list_2 = []ii=1while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0] list_2.append(each_id[0]) ii += 1 if (ii % 10000 == 0): print(ii)#print(list_2[0]) #data2的dict &#123;id:text&#125;ii=0for i in list_2: if(i in list_1): pass else: f_video_text_hash.write(i + &apos;:::&apos; + dict_2[i] + &apos;
&apos;) ii += 1 if (ii % 10000 == 0): print(ii)f1_video_text.close()f2_video_text.close()f_video_text_hash.close() 手动将数据集1得到的video:::text和video:::url文件（video_text_hash.txt,video_url_hash.txt），和数据集2得到的video:::text和video:::url文件（video_text_hash_4.txt,video_url_hash.txt）合并得到最终video_text_hash.txt和video_url_hash.txt。最后一步：统计video_text_hash.txt里hashtag词频写入到handle_hash.txtcount.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546# 统计hash总数与词频import collectionsf_video_text_hash = open(&quot;video_text_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_handle_hash = open(&quot;handle_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []i=1while 1: line_video_text = f_video_text_hash.readline() if not line_video_text: break else: slotList += subString1(line_video_text) #将所有HashTag存进listresult = collections.Counter(slotList) #词频统计#print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) #词频统计结果转换成字符串并存文件 f_handle_hash.write(ss+&apos;
&apos;)f_video_text_hash.close()f_handle_hash.close() 目前只处理了这两类数据，数据集中还包含了用户信息之类的其他信息，发布在github.
